import{_ as t,c as a,o,ag as r}from"./chunks/framework.dvv-DFtf.js";const u=JSON.parse('{"title":"OpenCat 配置","description":"","frontmatter":{},"headers":[],"relativePath":"guide/clients/opencat.md","filePath":"guide/clients/opencat.md","lastUpdated":1772163360000}'),d={name:"guide/clients/opencat.md"};function n(i,e,s,c,l,p){return o(),a("div",null,[...e[0]||(e[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide\\clients\\opencat.md for this page in Markdown format</div><h1 id="opencat-配置" tabindex="-1">OpenCat 配置 <a class="header-anchor" href="#opencat-配置" aria-label="Permalink to &quot;OpenCat 配置&quot;">​</a></h1><p><a href="https://opencat.app" target="_blank" rel="noreferrer">OpenCat</a> 是 iOS / macOS 原生 AI 聊天应用，界面简洁，支持自定义 API。</p><h2 id="快速配置-url-scheme" tabindex="-1">快速配置（URL Scheme） <a class="header-anchor" href="#快速配置-url-scheme" aria-label="Permalink to &quot;快速配置（URL Scheme）&quot;">​</a></h2><p>在浏览器或备忘录中点击以下链接，可一键跳转到 OpenCat 并自动填入配置：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opencat://team/join?domain=https://api.lurus.cn&amp;token=YOUR_API_KEY</span></span></code></pre></div><p>将 <code>YOUR_API_KEY</code> 替换为你的 Key（<code>sk-xxxxxxxxxxxxxxxx</code>），在 Safari 中打开即可。</p><div class="tip custom-block"><p class="custom-block-title">iOS 捷径（推荐）</p><p>在 iOS 捷径 App 中新建一个「打开 URL」动作，粘贴上方地址并填入你的 Key，保存到主屏幕，下次换设备也能一键完成配置。</p></div><hr><h2 id="手动配置" tabindex="-1">手动配置 <a class="header-anchor" href="#手动配置" aria-label="Permalink to &quot;手动配置&quot;">​</a></h2><p>若 URL Scheme 无效（旧版 OpenCat 不支持），手动配置：</p><ol><li>打开 OpenCat → <strong>设置</strong>（右上角头像）→ <strong>API 设置</strong></li><li>选择「<strong>自定义 API</strong>」，填入： <ul><li><strong>API Host</strong>：<code>https://api.lurus.cn</code></li><li><strong>API Key</strong>：你的 Key（<code>sk-xxxxxxxxxxxxxxxx</code>）</li></ul></li><li>点击「<strong>验证连接</strong>」，提示成功后保存</li></ol><hr><h2 id="选择模型" tabindex="-1">选择模型 <a class="header-anchor" href="#选择模型" aria-label="Permalink to &quot;选择模型&quot;">​</a></h2><p>OpenCat 不会自动拉取模型列表，需手动输入模型名称。常用模型：</p><table tabindex="0"><thead><tr><th>模型名称</th><th>特点</th></tr></thead><tbody><tr><td><code>deepseek-chat</code></td><td>高性价比，中文最佳</td></tr><tr><td><code>deepseek-reasoner</code></td><td>数学、代码推理</td></tr><tr><td><code>gpt-4o</code></td><td>综合能力最强</td></tr><tr><td><code>claude-3-5-sonnet</code></td><td>长文本、创意写作</td></tr><tr><td><code>gemini-3-pro-preview</code></td><td>多模态，1M 上下文</td></tr></tbody></table><p>完整列表见 <a href="/guide/models">支持的模型</a>。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="连接测试失败-提示-无效密钥" tabindex="-1">连接测试失败，提示&quot;无效密钥&quot; <a class="header-anchor" href="#连接测试失败-提示-无效密钥" aria-label="Permalink to &quot;连接测试失败，提示&quot;无效密钥&quot;&quot;">​</a></h3><ul><li>确认 API Host 末尾<strong>不带斜杠</strong>（<code>https://api.lurus.cn</code>，不是 <code>https://api.lurus.cn/</code>）</li><li>确认 API Key 格式正确（以 <code>sk-</code> 开头）</li><li>在 <a href="https://api.lurus.cn" target="_blank" rel="noreferrer">Lurus 控制台</a> 确认 Key 状态为「启用」</li></ul><h3 id="模型名称输入后无响应" tabindex="-1">模型名称输入后无响应 <a class="header-anchor" href="#模型名称输入后无响应" aria-label="Permalink to &quot;模型名称输入后无响应&quot;">​</a></h3><ul><li>检查模型名称拼写（区分大小写，如 <code>gpt-4o</code> 不是 <code>GPT-4o</code>）</li><li>确认你的 Key 有该模型的访问权限</li></ul><h3 id="macos-版配置在哪里" tabindex="-1">macOS 版配置在哪里？ <a class="header-anchor" href="#macos-版配置在哪里" aria-label="Permalink to &quot;macOS 版配置在哪里？&quot;">​</a></h3><p>macOS 版入口：菜单栏 <strong>OpenCat</strong> → <strong>Preferences</strong>（<code>⌘,</code>）→ <strong>API</strong> 选项卡，与 iOS 版配置参数相同。</p>',25)])])}const x=t(d,[["render",n]]);export{u as __pageData,x as default};
